  malphite: { diff: "EVEN", tone: "#e8b84b", tldr: "He stacks armor \u2014 your kit is magic, shroom %HP-poke.", breakdown: "Malphite stacks armor but you\u2019re magic. Shroom + poison %HP-poke him, blind his W-autos, and dodge his R.", dos: ["Shroom %HP-poke (magic)", "Blind (Q) his W-autos", "Dodge his R engage"], donts: ["Auto-trade his passive", "Eat his R knockup", "Get stuck in melee"], key: { slot: "R", name: "Unstoppable Force", cd: "130s", note: "Un-dodgeable burst. Blind + kite it.", winT: "ULT DOWN", winS: "Blind + poke him." }, hold: "Hold Q to blind him when he W-trades \u2014 your magic %HP-poke ignores his armor.", tip: "He stacks armor but you\u2019re magic \u2014 shroom %HP-poke him, blind his W-autos, and dodge his R.", win: "Shroom %HP-poke (magic) him down." },
