  ornn: { diff: "EVEN", tone: "#e8b84b", tldr: "Shroom %HP-poke his early \u2014 build pen, dodge his Q.", breakdown: "Both scale. Shroom + poison %HP-poke his early, build pen, and dodge his Q.", dos: ["Shroom %HP-poke his early", "Build magic pen", "Dodge his Q knockup"], donts: ["Stand near walls for his Q", "Get brittle-procced", "Get stuck in melee"], key: { slot: "Q", name: "Volcanic Rupture", cd: "10s", note: "Wall-knockup setup. Dodge it.", winT: "RUPTURE DOWN", winS: "Blind + poke him." }, hold: "Hold Q to blind him out of his brittle combo \u2014 shroom %HP-poke his early and dodge his Q.", tip: "Both scale \u2014 shroom %HP-poke his early, build pen, and dodge his Q.", win: "Shroom %HP-poke his early." },
  poppy: { diff: "EVEN", tone: "#e8b84b", tldr: "Blind her autos \u2014 shroom + poke, dodge her E.", breakdown: "Blind her autos, shroom + poison-poke from range, and dodge her E wall-stun.", dos: ["Blind (Q) her autos", "Shroom-poke from range", "Dodge her E wall-stun"], donts: ["Get E-wall-stunned", "Get R-knocked mid-poke", "Get stuck in melee"], key: { slot: "E", name: "Heroic Charge", cd: "14s", note: "Wall-pin stun. Dodge it.", winT: "CHARGE DOWN", winS: "Blind + poke her." }, hold: "Hold Q to blind her engage \u2014 the blind cuts her auto damage; shroom-poke from range.", tip: "Blind her autos, shroom-poke from range, and dodge her E wall-stun.", win: "Blind + shroom-poke her." },
  shen: { diff: "EVEN", tone: "#e8b84b", tldr: "Blind his autos \u2014 shroom his 1v1, track his R.", breakdown: "Blind his autos (and his W-block window), shroom-poke his weak 1v1, and track his R roams.", dos: ["Blind (Q) his autos", "Shroom-poke his 1v1", "Track his R roams"], donts: ["Get taunted into his W", "Fight his W block", "Ignore his R"], key: { slot: "E", name: "Shadow Dash (Taunt)", cd: "18s", note: "His engage CC. Dodge it.", winT: "TAUNT DOWN", winS: "Blind + poke him." }, hold: "Hold Q to blind him after his taunt \u2014 shroom-poke his weak 1v1; ping his R roams.", tip: "Blind his autos, shroom-poke his weak 1v1, and ping his R roams.", win: "Blind + shroom-poke his 1v1." },
