  tahmkench: { diff: "EVEN", tone: "#e8b84b", tldr: "Blind his autos \u2014 shroom-poke, dodge his tongue.", breakdown: "Blind his autos, shroom-poke from range, dodge his Q tongue, and kite his W dive.", dos: ["Blind (Q) his autos", "Shroom-poke from range", "Dodge his Q tongue"], donts: ["Get Q-stunned", "Fight into his W reactivate", "Get stuck in melee"], key: { slot: "Q", name: "Tongue Lash", cd: "7s", note: "His stun. Dodge it.", winT: "Q DOWN", winS: "Blind + poke him." }, hold: "Hold Q to blind him when he W-dives \u2014 the blind cuts his auto damage; shroom-poke and dodge his tongue.", tip: "Blind his autos, shroom-poke from range, dodge his Q tongue, and kite his W dive.", win: "Blind + shroom-poke him." },
  zac: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 shroom %HP-poke, dodge his E, anti-heal.", breakdown: "Build MR, shroom + poison %HP-poke, dodge his E slingshot, and anti-heal his sustain.", dos: ["Build MR", "Shroom %HP-poke from range", "Anti-heal his sustain"], donts: ["Let him eat blobs", "Get E-knocked-up", "Get stuck in melee"], key: { slot: "E", name: "Elastic Slingshot", cd: "16s", note: "His engage. Blind + kite it.", winT: "SLINGSHOT DOWN", winS: "Blind + poke him." }, hold: "Hold Q to blind him as he slingshots in \u2014 build MR; shroom %HP-poke and anti-heal.", tip: "Build MR, shroom %HP-poke from range, dodge his E, and anti-heal his sustain.", win: "Build MR and shroom %HP-poke him." },
