  jayce: { diff: "TRICKY", tone: "#ff8b3d", tldr: "He pokes you out \u2014 build MR, shroom + poke back.", breakdown: "Jayce out-pokes you. Build MR, dodge his Q, shroom his approach, and poke back.", dos: ["Build MR", "Dodge his Q poke", "Shroom his approach"], donts: ["Walk into his Q-gate", "Get E-knocked", "Get stuck in poke range"], key: { slot: "Q", name: "Shock Blast", cd: "6s", note: "His main poke. Dodge it.", winT: "SHOCK BLAST DOWN", winS: "Blind + poke him." }, hold: "Hold Q to blind him when he commits to melee form \u2014 build MR; shroom his approach paths.", tip: "Build MR, dodge his Q, shroom his approach, and poke back with autos + shrooms.", win: "Build MR and shroom + poke him." },
  kayle: { diff: "FAVOURED", tone: "#3ddc97", tldr: "Crush her early \u2014 blind her autos, deny her CS.", breakdown: "Kayle is helpless early. Blind her autos, shroom-poke her off CS, and all-in before her R.", dos: ["Blind (Q) her autos", "Shroom-poke her off CS", "All-in before her R"], donts: ["Let her free-farm", "Fight late vs her R", "Get stuck in melee"], key: { slot: "R", name: "Divine Judgment (Invuln)", cd: "100s", note: "Her get-out at 6. Bait it.", winT: "JUDGMENT DOWN", winS: "Blind + poke her." }, hold: "Hold Q to blind her in a trade \u2014 the blind cuts her early DPS; shroom-poke her off CS.", tip: "She\u2019s helpless early \u2014 blind her autos, shroom-poke her off CS, and all-in before her R.", win: "Blind + shroom-poke her early." },
