  quinn: { diff: "EVEN", tone: "#e8b84b", tldr: "Blind war \u2014 build MR, out-poke her, dodge her vault.", breakdown: "Both blind. Build MR, out-poke her with shrooms, blind HER autos, and dodge her vault.", dos: ["Build MR", "Out-poke with shrooms", "Blind (Q) her autos"], donts: ["Auto into her blind", "Let her kite you out", "Get stuck in melee"], key: { slot: "E", name: "Vault (Dash/Blind)", cd: "11s", note: "Her self-peel. Blind her back.", winT: "VAULT DOWN", winS: "Blind + poke her." }, hold: "Hold Q to blind her autos back \u2014 it\u2019s a blind war; out-poke her with shrooms.", tip: "It\u2019s a blind war \u2014 build MR, out-poke her with shrooms, blind her autos, and dodge her vault.", win: "Win the blind war and out-poke her." },
