  swain: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 shroom-poke, dodge his E root.", breakdown: "Build MR, shroom-poke from range, dodge his E root, and anti-heal his R drain.", dos: ["Build MR + anti-heal", "Shroom-poke from range", "Dodge his E root"], donts: ["Fight into his R drain", "Get E-rooted", "Get stuck in melee"], key: { slot: "R", name: "Demonic Ascension", cd: "100s", note: "His drain. Poke when it\u2019s down.", winT: "ASCENSION DOWN", winS: "Blind + poke him." }, hold: "Hold Q to blind him when he E-roots in \u2014 build MR; shroom-poke and anti-heal his R.", tip: "Build MR, shroom-poke from range, dodge his E root, and anti-heal his R drain.", win: "Build MR and shroom-poke him." },
  teemo: { diff: "MIRROR", tone: "#e8b84b", tldr: "Teemo mirror \u2014 whoever wins the blind war and shroom-control wins.", breakdown: "Pure Teemo mirror: it\u2019s a blind and shroom-control war. Whoever blinds the other\u2019s autos and controls shroom vision wins.", dos: ["Win the blind war", "Control shroom vision", "Build MR"], donts: ["Get blinded first", "Walk into his shrooms", "Fall behind in farm"], key: { slot: "Q", name: "Blinding Dart", cd: "7s", note: "Whoever wins the blind + shroom war wins.", winT: "BLIND DOWN", winS: "Blind + poke him." }, hold: "Hold Q to blind his autos first \u2014 whoever wins the blind war and controls shroom vision wins.", tip: "It\u2019s a blind + shroom mirror \u2014 blind his autos first, control shroom vision, and build MR.", win: "Win the blind war and shroom-control." },
  vladimir: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 shroom-poke, bully his early, bait pool.", breakdown: "Vlad is weak early. Build MR, shroom-poke and bully his weak early, and bait his pool.", dos: ["Shroom-poke and bully early", "Build MR + anti-heal", "Bait his pool"], donts: ["Let him pool your poke", "Stack pure HP vs %damage", "Let him free-scale"], key: { slot: "W", name: "Sanguine Pool", cd: "22s", note: "Dodges your poke. Bait it.", winT: "POOL DOWN", winS: "Blind + poke him." }, hold: "Hold Q to blind him in a trade \u2014 bait his pool first, then poke when it\u2019s down; build MR.", tip: "He\u2019s weak early \u2014 shroom-poke and bully him, bait his pool, and build MR.", win: "Bully him early and bait his pool." },
