  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"EVEN","tone":"#e8b84b","tldr":"Weather the poke — blind his Heroic Swing and poison every path he walks.","breakdown":"Akshan plays around Heroic Swing. Q-blind erases his auto window, E-poison stacks the chip, and post-6 the shroom net makes ganks and all-ins self-destruct. Doran’s Shield blunts the poke war.","dos":["Q-blind his Heroic Swing trade","AA-poke between his reaches","Shroom his paths from 6"],"donts":["Shroom lane-center only","Trade with Q down","Stand in his engage range"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Blind the trade, shroom the map."},"win":"Blind his Heroic Swing and poison every path he walks."},
